/**
 * Authentication Module Types
 *
 * Type definitions for the Auth module including:
 * - Registration/Login DTOs
 * - Token types and payloads
 * - Session management types
 * - Password reset types
 * - Email verification types
 *
 * @module modules/_core/auth/types
 *
 * @example
 * ```typescript
 * import type {
 *   LoginRequest,
 *   AuthTokens,
 *   SessionInfo,
 * } from '@/modules/_core/auth/auth.types';
 *
 * async function login(data: LoginRequest): Promise<AuthTokens> { ... }
 * ```
 */

// -----------------------------------------------------------------------------
// Registration Types
// -----------------------------------------------------------------------------

/**
 * User registration request data
 */
export interface RegisterRequest {
  /** User email address */
  email: string;
  /** Plain text password */
  password: string;
  /** Password confirmation */
  passwordConfirm: string;
  /** User's first name */
  firstName: string;
  /** User's last name */
  lastName: string;
  /** User's phone number (optional) */
  phone?: string;
  /** Accept terms and conditions */
  acceptTerms: boolean;
  /** Marketing consent (optional) */
  acceptMarketing?: boolean;
}

/**
 * Registration response data
 */
export interface RegisterResponse {
  /** Created user ID */
  userId: string;
  /** User email */
  email: string;
  /** Whether email verification is required */
  requiresEmailVerification: boolean;
  /** Success message */
  message: string;
}

// -----------------------------------------------------------------------------
// Login Types
// -----------------------------------------------------------------------------

/**
 * User login request data
 */
export interface LoginRequest {
  /** User email address */
  email: string;
  /** Plain text password */
  password: string;
  /** Remember me option (extends token expiry) */
  rememberMe?: boolean;
}

/**
 * Login response with tokens
 */
export interface LoginResponse {
  /** User information */
  user: AuthenticatedUser;
  /** Authentication tokens */
  tokens: AuthTokens;
}

/**
 * Authenticated user information
 */
export interface AuthenticatedUser {
  /** User ID */
  id: string;
  /** User email */
  email: string;
  /** User's first name */
  firstName: string;
  /** User's last name */
  lastName: string;
  /** User's avatar URL (optional) */
  avatar?: string;
  /** Organization ID (null for platform users) */
  organizationId: string | null;
  /** Organization name (null for platform users) */
  organizationName?: string | null;
  /** User's primary role */
  role: string;
  /** User's permissions array */
  permissions: string[];
  /** Email verified status */
  emailVerified: boolean;
}

// -----------------------------------------------------------------------------
// Token Types
// -----------------------------------------------------------------------------

/**
 * Authentication tokens pair
 */
export interface AuthTokens {
  /** JWT access token (short-lived) */
  accessToken: string;
  /** JWT refresh token (long-lived, stored in httpOnly cookie) */
  refreshToken: string;
  /** Access token expiry time in milliseconds */
  expiresIn: number;
  /** Token type (always 'Bearer') */
  tokenType: 'Bearer';
}

/**
 * JWT access token payload structure
 */
export interface AccessTokenPayload {
  /** User ID (subject claim) */
  sub: string;
  /** Organization ID */
  org: string;
  /** User's primary role */
  role: string;
  /** Cached permissions array */
  permissions: string[];
  /** Token ID for revocation tracking */
  jti: string;
  /** Issued at timestamp (seconds) */
  iat: number;
  /** Expiry timestamp (seconds) */
  exp: number;
}

/**
 * JWT refresh token payload structure
 */
export interface RefreshTokenPayload {
  /** User ID (subject claim) */
  sub: string;
  /** Token ID for revocation tracking */
  jti: string;
  /** Token type marker */
  type: 'refresh';
  /** Issued at timestamp (seconds) */
  iat: number;
  /** Expiry timestamp (seconds) */
  exp: number;
}

/**
 * Token refresh request
 */
export interface RefreshTokenRequest {
  /** Current refresh token (can come from cookie or body) */
  refreshToken?: string;
}

/**
 * Token refresh response
 */
export interface RefreshTokenResponse {
  /** New authentication tokens */
  tokens: AuthTokens;
}

// -----------------------------------------------------------------------------
// Session Types
// -----------------------------------------------------------------------------

/**
 * User session information
 */
export interface SessionInfo {
  /** Session ID */
  id: string;
  /** User ID */
  userId: string;
  /** Organization ID */
  organizationId: string | null;
  /** User role at session creation */
  role: string;
  /** Token ID for this session */
  tokenId: string;
  /** Client IP address */
  ipAddress?: string;
  /** User agent string */
  userAgent?: string;
  /** Parsed device info */
  device?: DeviceInfo;
  /** Session creation timestamp */
  createdAt: string;
  /** Last activity timestamp */
  lastActivityAt: string;
  /** Whether this is the current session */
  isCurrent?: boolean;
}

/**
 * Parsed device information from user agent
 */
export interface DeviceInfo {
  /** Device type (desktop, mobile, tablet) */
  type: 'desktop' | 'mobile' | 'tablet' | 'unknown';
  /** Browser name */
  browser?: string;
  /** Browser version */
  browserVersion?: string;
  /** Operating system */
  os?: string;
  /** OS version */
  osVersion?: string;
}

/**
 * Session revocation request
 */
export interface RevokeSessionRequest {
  /** Session ID to revoke */
  sessionId: string;
}

/**
 * Revoke all sessions request
 */
export interface RevokeAllSessionsRequest {
  /** Exclude current session from revocation */
  excludeCurrent?: boolean;
}

// -----------------------------------------------------------------------------
// Password Reset Types
// -----------------------------------------------------------------------------

/**
 * Password reset request (forgot password)
 */
export interface ForgotPasswordRequest {
  /** User email address */
  email: string;
}

/**
 * Password reset response
 */
export interface ForgotPasswordResponse {
  /** Success message (always same to prevent user enumeration) */
  message: string;
}

/**
 * Password reset token verification
 */
export interface VerifyResetTokenRequest {
  /** Password reset token from email */
  token: string;
}

/**
 * Password reset completion request
 */
export interface ResetPasswordRequest {
  /** Password reset token from email */
  token: string;
  /** New password */
  password: string;
  /** Password confirmation */
  passwordConfirm: string;
}

/**
 * Password reset completion response
 */
export interface ResetPasswordResponse {
  /** Success message */
  message: string;
}

/**
 * Change password request (for authenticated users)
 */
export interface ChangePasswordRequest {
  /** Current password */
  currentPassword: string;
  /** New password */
  newPassword: string;
  /** New password confirmation */
  newPasswordConfirm: string;
}

/**
 * Change password response
 */
export interface ChangePasswordResponse {
  /** Success message */
  message: string;
  /** Whether all sessions were revoked */
  sessionsRevoked: boolean;
}

// -----------------------------------------------------------------------------
// Email Verification Types
// -----------------------------------------------------------------------------

/**
 * Email verification request
 */
export interface VerifyEmailRequest {
  /** Email verification token from email */
  token: string;
}

/**
 * Email verification response
 */
export interface VerifyEmailResponse {
  /** Success message */
  message: string;
  /** Whether email was verified */
  verified: boolean;
}

/**
 * Resend email verification request
 */
export interface ResendVerificationRequest {
  /** User email address */
  email: string;
}

/**
 * Resend email verification response
 */
export interface ResendVerificationResponse {
  /** Success message (always same to prevent user enumeration) */
  message: string;
}

// -----------------------------------------------------------------------------
// Logout Types
// -----------------------------------------------------------------------------

/**
 * Logout request (optional, token from header/cookie)
 */
export interface LogoutRequest {
  /** Whether to logout from all devices */
  allDevices?: boolean;
}

/**
 * Logout response
 */
export interface LogoutResponse {
  /** Success message */
  message: string;
}

// -----------------------------------------------------------------------------
// Token Data Types (Internal/Redis)
// -----------------------------------------------------------------------------

/**
 * Stored refresh token data in Redis
 */
export interface StoredRefreshTokenData {
  /** User ID */
  userId: string;
  /** Organization ID */
  organizationId: string | null;
  /** Access token ID linked to this refresh token */
  accessTokenId: string;
  /** Token creation timestamp */
  createdAt: string;
}

/**
 * Stored password reset token data in Redis
 */
export interface StoredResetTokenData {
  /** User ID */
  userId: string;
  /** User email */
  email: string;
  /** Token creation timestamp */
  createdAt: string;
}

/**
 * Stored email verification token data in Redis
 */
export interface StoredVerificationTokenData {
  /** User ID */
  userId: string;
  /** Email to verify */
  email: string;
  /** Token creation timestamp */
  createdAt: string;
}

// -----------------------------------------------------------------------------
// Auth Events
// -----------------------------------------------------------------------------

/**
 * Auth login event payload
 */
export interface AuthLoginEvent {
  /** User ID */
  userId: string;
  /** Organization ID */
  organizationId: string | null;
  /** Session ID */
  sessionId: string;
  /** Client IP address */
  ipAddress?: string;
  /** User agent */
  userAgent?: string;
  /** Timestamp */
  timestamp: string;
}

/**
 * Auth logout event payload
 */
export interface AuthLogoutEvent {
  /** User ID */
  userId: string;
  /** Session ID (null if all sessions) */
  sessionId: string | null;
  /** Whether all sessions were revoked */
  allSessions: boolean;
  /** Timestamp */
  timestamp: string;
}

/**
 * Password reset requested event payload
 */
export interface PasswordResetRequestedEvent {
  /** User ID */
  userId: string;
  /** User email */
  email: string;
  /** Client IP address */
  ipAddress?: string;
  /** Timestamp */
  timestamp: string;
}

/**
 * Password reset completed event payload
 */
export interface PasswordResetCompletedEvent {
  /** User ID */
  userId: string;
  /** Whether sessions were revoked */
  sessionsRevoked: boolean;
  /** Timestamp */
  timestamp: string;
}

/**
 * Email verification completed event payload
 */
export interface EmailVerificationCompletedEvent {
  /** User ID */
  userId: string;
  /** Verified email */
  email: string;
  /** Timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Auth Hook Types
// -----------------------------------------------------------------------------

/**
 * Before login hook context
 */
export interface BeforeLoginContext {
  /** Login request data */
  request: LoginRequest;
  /** Client IP address */
  ipAddress?: string;
  /** User agent */
  userAgent?: string;
}

/**
 * After login hook context
 */
export interface AfterLoginContext {
  /** Authenticated user */
  user: AuthenticatedUser;
  /** Generated tokens */
  tokens: AuthTokens;
  /** Session info */
  session: SessionInfo;
}

/**
 * Before token refresh hook context
 */
export interface BeforeTokenRefreshContext {
  /** User ID from refresh token */
  userId: string;
  /** Refresh token ID */
  refreshTokenId: string;
}

/**
 * After token refresh hook context
 */
export interface AfterTokenRefreshContext {
  /** User ID */
  userId: string;
  /** New tokens */
  tokens: AuthTokens;
}

// -----------------------------------------------------------------------------
// Auth Settings Types
// -----------------------------------------------------------------------------

/**
 * Auth module settings
 */
export interface AuthModuleSettings {
  /** Access token expiry (e.g., '15m') */
  accessTokenExpiry: string;
  /** Refresh token expiry (e.g., '7d') */
  refreshTokenExpiry: string;
  /** Minimum password length */
  passwordMinLength: number;
  /** Require uppercase letter */
  passwordRequireUppercase: boolean;
  /** Require lowercase letter */
  passwordRequireLowercase: boolean;
  /** Require number */
  passwordRequireNumber: boolean;
  /** Require special character */
  passwordRequireSpecial: boolean;
  /** Max login attempts before lockout */
  maxLoginAttempts: number;
  /** Lockout duration in seconds */
  lockoutDuration: number;
  /** Maximum concurrent sessions per user */
  sessionMaxCount: number;
  /** Enable email verification requirement */
  enableEmailVerification: boolean;
  /** Enable password reset functionality */
  enablePasswordReset: boolean;
}

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

/**
 * Type guard to check if a token payload is an access token
 */
export function isAccessTokenPayload(
  payload: AccessTokenPayload | RefreshTokenPayload
): payload is AccessTokenPayload {
  return 'org' in payload && 'role' in payload && 'permissions' in payload;
}

/**
 * Type guard to check if a token payload is a refresh token
 */
export function isRefreshTokenPayload(
  payload: AccessTokenPayload | RefreshTokenPayload
): payload is RefreshTokenPayload {
  return 'type' in payload && payload.type === 'refresh';
}
